__kernel void likelihood_kernel(__global double * arrayX, __global double * arrayY, __global double * xj, __global double * yj, __global double * CDF, __global int * ind, __global int * objxy, __global double * likelihood, __global unsigned char * I, __global double * u, __global double * weights, int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, __global int *seed, __global double* partial_sums) {
