        }
        likelihood[i] = likelihoodSum / countOnes;

        weights[i] = weights[i] * exp(likelihood[i]);
    }

    buffer[get_local_id(0)] = 0.0;

    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
